// Parse incoming Telegram update for Content Plan Editor
const body = $input.first().json;
let action = 'ignore';
let postId = '';
let changes = '';
let chatId = '';

// 1. Handle callback_query: edit_plan
if (body.callback_query) {
  const data = body.callback_query.data || '';
  if (data === 'edit_plan') {
    action = 'prompt';
    chatId = String(body.callback_query.message?.chat?.id || '');
  }
}

// 2. Handle text message
if (body.message && body.message.text) {
  const text = body.message.text.trim();
  chatId = String(body.message.chat?.id || '');

  // PostID pattern: e.g. CAR-20260330-001, REL-20260331-001
  const postIdPattern = /^Change\s+([A-Z]+-\d{8}-\d+)\s*$/i;
  const changePattern = /^Change\s+(.+)$/i;

  const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
  const results = [];
  let currentPostId = null;

  for (const line of lines) {
    const postIdMatch = line.match(postIdPattern);
    if (postIdMatch) {
      // This line is a PostID line
      currentPostId = postIdMatch[1].trim();
    } else {
      const changeMatch = line.match(changePattern);
      if (changeMatch && currentPostId) {
        // This line is the change instruction for the current PostID
        results.push({
          action: 'edit',
          postId: currentPostId,
          changes: changeMatch[1].trim(),
          chatId
        });
        currentPostId = null;
      }
    }
  }

  if (results.length > 0) {
    return results.map(r => ({ json: r }));
  }
}

// Fallback return (handles: ignore, prompt, unmatched message)
return [{ json: { action, postId, changes, chatId } }];

// Build AI prompt for editing a specific post
 const parsed = $('Loop Over Items').first().json;
const postId = parsed.postId;
const changes = parsed.changes;
const chatId = parsed.chatId;

// Read the existing post from calendar
const calRows = $('Read Calendar').all().map(i => i.json);
const existingPost = calRows.find(r => r.PostID === postId);
if (!existingPost) {
  return [{ json: {
    chatId, error: true,
    errorMsg: `❌ Post ID \`${postId}\` not found in the Content Calendar.`
  }}];
}

// Read config
const cfg = $('Read Config').first().json;
const lang = cfg.contentlanguage || cfg['Content Language'] || 'English';
const tone = cfg.tone || 'Professional';
const audience = cfg.audience || 'General';
const blacklist = cfg.blacklistWords || '';
const minCaptionWords = cfg.minCaptionWords || 80;
const maxCaptionWords = cfg.maxCaptionWords || 200;
const maxHookChars = cfg.maxHookChars || 100;
const minHashtags = cfg.minHashtags || 10;
const maxHashtags = cfg.maxHashtags || 20;

// Read products
const products = $('Read Products').all().map(i => i.json)
  .filter(p => p.Status === 'Active' || p.Status === 'Seasonal');
let productContext = '';
if (products.length > 0) {
  productContext = '\n\nAVAILABLE PRODUCTS:\n';
  products.forEach((p, i) => {
    productContext += `${i+1}. ${p.Name} (${p.Category}) - ${p.Description || ''}\n`;
  });
}

// Build the existing post as a formatted block
const existingFields = JSON.stringify(existingPost, null, 2);

// ─── SYSTEM PROMPT ───────────────────────────────────────────────────────────
const systemPrompt = `You are a senior social media strategist editing an existing Instagram post for the brand ${cfg.brandName || 'Beauty Brand'}.

BRAND VOICE:
- Tone: ${tone}
- Avoid casual language, slang, or these forbidden words: ${blacklist || 'none'}

TARGET AUDIENCE: ${audience}

CONTENT LANGUAGE: ${lang} — ALL generated or modified text MUST be in ${lang}.

═══════════════════════════════════════════════════════
⚠️  CRITICAL EDITING RULE — READ BEFORE ANYTHING ELSE:
═══════════════════════════════════════════════════════

You are an EDITOR, not a content creator. Your job is SURGICAL.

1. IDENTIFY which specific fields the client asked to change.
2. MODIFY only those exact fields.
3. For EVERY other field: copy the original value EXACTLY, character-for-character — ZERO changes, no rephrasing, no improving, no "optimizing."

This means:
- If only Caption is requested → Topic, Hook, CTA, Hashtags, VisualBrief stay FROZEN.
- If only Hook is requested → Caption, Topic, etc. stay FROZEN.
- NEVER assume you should "also improve" something that was not requested.
- NEVER paraphrase or enhance a field that was not explicitly mentioned in the client's request.

FIELD CONSTRAINTS (apply ONLY to fields being modified):
- Caption: ${minCaptionWords}–${maxCaptionWords} words
- Hook: max ${maxHookChars} characters
- Hashtags: ${minHashtags}–${maxHashtags} tags, space-separated
- All modified text must be in ${lang}

Return ONLY a valid JSON object with ALL fields. No text before or after the JSON.`;

// ─── USER PROMPT ─────────────────────────────────────────────────────────────
const userPrompt = `You are editing an existing Instagram post. A client has requested specific changes.

EXISTING POST DATA (treat every field here as the ground truth):
${existingFields}

CLIENT REQUESTED CHANGES:
${changes}

YOUR TASK:
1. Read the client request carefully and identify ONLY the fields that need to change.
2. For fields that need to change: generate new content following brand voice, constraints, and the client's intent.
3. For ALL other fields: copy the value from EXISTING POST DATA above — verbatim, unchanged.

FIELDS THAT MUST ALWAYS STAY FROZEN (never modify these under any circumstances):
- PostID
- ContentType
- ScheduledDate
- ScheduledTime
- Day
- Pillar
- PreferredTemplate
- PreferredTemplateId

FIELDS THAT ARE FROZEN UNLESS THE CLIENT EXPLICITLY MENTIONED THEM:
- Topic       → only change if client said "change topic" or "change the title"
- Hook        → only change if client said "change hook" or "change the opening line"
- CTA         → only change if client said "change CTA" or "change call to action"
- Hashtags    → only change if client said "change hashtags"
- VisualBrief → only change if client said "change visual" or "change the brief"
- ProductFeatured → only change if client said "change product"
${productContext}
Return ONLY this JSON object with ALL fields filled. No text before or after:
{
  "PostID": "${postId}",
  "ContentType": "",
  "ScheduledDate": "",
  "ScheduledTime": "",
  "Day": "",
  "Topic": "",
  "Hook": "",
  "Caption": "",
  "Hashtags": "space-separated hashtags string",
  "CTA": "",
  "VisualBrief": "",
  "ProductFeatured": "",
  "Pillar": "",
  "PreferredTemplate": "",
  "PreferredTemplateId": "",
  "AnalyticsInsight": "Explain ONLY what was changed and why — do not mention fields that were preserved."
}`;

// ─── ASSEMBLE OPENAI BODY ─────────────────────────────────────────────────────
const oaiBody = JSON.stringify({
  model: 'gpt-4o',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ],
  temperature: 0.5,
  max_tokens: 2000
});

return [{ json: {
  chatId,
  postId,
  changes,
  existingPost,
  openAiBody: oaiBody,
  systemPrompt,
  userPrompt,
  error: false
}}];

// Parse AI response and prepare for sheet update
const inp = $input.first().json;
const editData = $('Build Edit Prompt').first().json;
const chatId = editData.chatId;
const postId = editData.postId;
const existingPost = editData.existingPost;

let txt = '';

if (inp.choices) {
  // OpenAI / gpt-4o format
  txt = inp.choices[0].message.content;
} else if (inp.candidates) {
  // Raw Gemini REST API format
  txt = inp.candidates[0].content.parts[0].text;
} else if (inp.content && inp.content.parts) {
  // n8n "Message a model" Gemini node format
  txt = inp.content.parts[0].text;
} else {
  return [{ json: { chatId, error: true, errorMsg: '❌ AI returned no valid response.' }}];
}

// Clean markdown code fences
const tick = String.fromCharCode(96);
txt = txt
  .replace(new RegExp(tick + '{3}json\\s*', 'g'), '')
  .replace(new RegExp(tick + '{3}\\s*', 'g'), '')
  .trim();

let updatedPost;
try {
  updatedPost = JSON.parse(txt);
  if (Array.isArray(updatedPost)) updatedPost = updatedPost[0];
} catch(e) {
  return [{ json: {
    chatId, error: true,
    errorMsg: `❌ Failed to parse AI response: ${e.message}`
  }}];
}

// Ensure PostID is preserved
updatedPost.PostID = postId;
updatedPost.Status = 'edited';
updatedPost.EditedAt = new Date().toISOString();

// Build before/after report
let doc = '✏️ CONTENT PLAN EDIT REPORT\n';
doc += `Post ID: ${postId}\n`;
doc += `Edited: ${new Date().toISOString().replace('T', ' ').substring(0, 19)}\n`;
doc += '═══════════════════════════════════════\n\n';
doc += '📝 CHANGES REQUESTED:\n';
doc += `${editData.changes}\n\n`;
doc += '─────────────────────────────────\n\n';

const compareFields = ['Topic', 'Hook', 'Caption', 'Hashtags', 'CTA',
  'VisualBrief', 'ProductFeatured', 'Pillar', 'PreferredTemplate', 'AnalyticsInsight'];

compareFields.forEach(field => {
  const oldVal = (existingPost[field] || existingPost[field.replace(/([A-Z])/g, ' $1').trim()] || '').toString();
  const newVal = (updatedPost[field] || '').toString();
  if (oldVal !== newVal) {
    doc += `📌 ${field}:\n`;
    doc += `  BEFORE: ${oldVal.substring(0, 200)}${oldVal.length > 200 ? '...' : ''}\n`;
    doc += `  AFTER:  ${newVal.substring(0, 200)}${newVal.length > 200 ? '...' : ''}\n\n`;
  }
});

doc += '\n═══════════════════════════════════════\n';
doc += '✅ Post has been updated in the Content Calendar!\n';

const fileName = `edit_report_${postId}.txt`;

// btoa with UTF-8 support (Buffer not available in n8n Task Runner)
const base64Data = btoa(unescape(encodeURIComponent(doc)));
const fileSize = doc.length;

// Prepare the sheet update row
const sheetRow = {
  PostID: updatedPost.PostID,
  ContentType: updatedPost.ContentType || existingPost.ContentType,
  ScheduledDate: updatedPost.ScheduledDate || existingPost.ScheduledDate,
  ScheduledTime: updatedPost.ScheduledTime || existingPost.ScheduledTime,
  Day: updatedPost.Day || existingPost.Day,
  Topic: updatedPost.Topic || existingPost.Topic,
  Hook: updatedPost.Hook || existingPost.Hook,
  Caption: updatedPost.Caption || existingPost.Caption,
  Hashtags: updatedPost.Hashtags || existingPost.Hashtags,
  CTA: updatedPost.CTA || existingPost.CTA,
  VisualBrief: updatedPost.VisualBrief || existingPost.VisualBrief,
  'Product Featured': updatedPost.ProductFeatured || existingPost.ProductFeatured || existingPost['Product Featured'] || '',
  Pillar: updatedPost.Pillar || existingPost.Pillar,
  'Preferred Template': updatedPost.PreferredTemplate || existingPost.PreferredTemplate || existingPost['Preferred Template'] || '',
  PreferredTemplateId: updatedPost.PreferredTemplateId || existingPost.PreferredTemplateId,
  Status: 'edited',
  AnalyticsInsight: updatedPost.AnalyticsInsight || '',
  NeedsReview: false,
  ReviewFlags: '',
  AISource: 'edit-gemini',
  EditedAt: new Date().toISOString()
};

return [{
  json: {
    chatId,
    postId,
    sheetRow,
    error: false,
    fileName
  },
  binary: {
    data: {
      data: base64Data,
      mimeType: 'text/plain; charset=utf-8',
      fileName,
      fileExtension: 'txt',
      fileSize: fileSize
    }
  }
}];

// Extract sheet row for Google Sheets update
const data = $('Parse AI Response').first().json;
return [{ json: data.sheetRow }];

// Bridge: pull binary from Parse AI Response and chatId
const data = $('Parse AI Response').first();
const chatId = data.json.chatId;
const binaryData = data.binary;

if (!binaryData || !binaryData.data) {
  return [{ json: { chatId, skip: true } }];
}

return [{
  json: { chatId },
  binary: binaryData
}];
